INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s n.os 1 e 2 por parte da entidade recrutadora, empregadora ou responsável pela atividade constitui contraordenação, punida com coima cujos limites mínimo e máximo são os previstos no artigo 17.º do regime que institui o ilícito de mera ordenação social e respetivo processo, aprovado pelo Decreto-Lei n.º 433/82, de 27 de outubro, podendo também ser aplicadas as sanções acessórias previstas nas alíneas b), c), e), f) e g) do n.º 1 do artigo 21.º, verificados os pressupostos previstos no artigo 21.º-A do mesmo diploma.
